jQuery(function($){function p(v){return v<10?"0"+v:""+v}$(".gd-event-countdown[data-countdown-to]").each(function(){var $el=$(this),target=new Date($el.attr("data-countdown-to")).getTime();if(isNaN(target)){return}var finished=$el.attr("data-finished")||"",action=$el.attr("data-finished-action")||"text",$numbers=$el.find("[data-countdown-number]"),timer;function tick(){var d=target-Date.now();if(d<=0){clearInterval(timer);if(action==="hide"){$el.hide()}else if(finished){$el.html($('<div class="gd-event-countdown__finished" />').text(finished))}$el.addClass("gd-event-countdown--finished");return}var v=[Math.floor(d/86400000),Math.floor(d%86400000/3600000),Math.floor(d%3600000/60000),Math.floor(d%60000/1000)];$numbers.each(function(i){if(i<v.length){$(this).text(p(v[i]))}})}tick();timer=setInterval(tick,1000)})});
